import { describe, expect, it } from "bun:test"
import { RpcError } from "starknet"

import { extractRpcErrorCode } from "../../services/starknet-utils"

describe("extractRpcErrorCode", () => {
  it("extracts code from starknet RpcError instance", () => {
    const rpcError = new RpcError(
      { code: 20, message: "Contract not found" },
      "starknet_call",
      {},
    )

    expect(extractRpcErrorCode(rpcError)).toBe(20)
  })

  it("extracts code from plain object with code property", () => {
    const error = { code: -32000, message: "server error" }

    expect(extractRpcErrorCode(error)).toBe(-32000)
  })

  it("extracts code from nested error.baseError.code", () => {
    const error = { baseError: { code: 40, message: "CONTRACT_ERROR" } }

    expect(extractRpcErrorCode(error)).toBe(40)
  })

  it("returns -1 for Error with no code", () => {
    const error = new Error("network timeout")

    expect(extractRpcErrorCode(error)).toBe(-1)
  })

  it("returns -1 for string error", () => {
    expect(extractRpcErrorCode("connection refused")).toBe(-1)
  })

  it("returns -1 for null/undefined", () => {
    expect(extractRpcErrorCode(null)).toBe(-1)
    expect(extractRpcErrorCode(undefined)).toBe(-1)
  })

  it("preserves code=0 (zero is valid, not falsy-filtered)", () => {
    const error = { code: 0, message: "ok" }

    expect(extractRpcErrorCode(error)).toBe(0)
  })
})

